scwin.onpageload = function () {
  scwin.lobranCd = $c.gus.cfIsNull($p, $c.data.getMemInfo($p, "lobranCd")) ? "" : $c.data.getMemInfo($p, "lobranCd"); // 물류 점소 코드
  scwin.vCurDate = $c.date.getServerDateTime($p, "yyyyMMdd"); // 서버를 기준으로 현재 날짜 반환
  scwin.varvStDt = scwin.vCurDate.substring(0, 6) + "01"; // 입항예정일자 from(현재 날짜가 포함된 달의 시작 일자)
  scwin.varvEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth($p, scwin.vCurDate.substring(0, 6)); // 입항예정일자 to(현재 날짜가 포함된 달의 마지막 일자)

  scwin.vBasSdId = "/ui/ds/op/stvwrk/op_210_01_02b.xml"; // 본선작업계획상세조회
  scwin.vBasMnId = "op_210_01_02b"; // 본선작업계획상세조회

  //파일 업로드 위치
  scwin.systemPathKey = DFWConstants.FILE_UPLOAD_SYSTEM_PATH;
  scwin.systemPathVal = "/cm/bc/cstmrcardmgnt/cstmrcardmgnt";
  scwin.curRow = "";
  scwin.curRow2 = "";
  scwin.tmp_colid = "";
  scwin.tmp_grdnm = "";
  scwin.tmp_staffNo = "";
  scwin.tmp_staffNm = "";
  const codeOptions = [{
    grpCd: "OP306",
    compID: "gr_cvsslInfo:wrkSeq"
  }, {
    grpCd: "SD060",
    compID: "gr_hold:impExpClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions, scwin.setCommonCodeCallBack);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  $p.setTimeout(function () {}, {
    "delay": 50
  });
};
scwin.setCommonCodeCallBack = async function () {
  co_ds_combo1_search.set("sysCd", "BerthNonUsableEBC");
  co_ds_combo1_search.set("queryId", "retriveLobranCodeList");
  var rs = await $c.sbm.execute($p, sbm_lobranCd);
  if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
    co_ds_combo1.setJSON(rs.responseJSON.GAUCE);
    co_ds_combo1.sort("code", 0);
    scwin.f_SetDefaultData();
  }
  ;
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {
  ica_arvStDt.setValue(scwin.varvStDt); // 입항예정일자 from		
  ica_arvEndDt.setValue(scwin.varvEndDt); // 입항예정일자 to	
  $c.gus.cfDisableAllBtn($p);
  acb_lobranCd.setValue(scwin.lobranCd);
  acb_lobranCd.focus();

  // $p.setTimeout(function() {
  //     acb_lobranCd.setValue("6AA");
  //     ica_arvStDt.setValue("20171124");
  //     ica_arvEndDt.setValue("20171124");
  // }, {"delay":50});
};

//-------------------------------------------------------------------------
// 본선작업계획현황조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  // 검색조건 필수 입력 체크
  if (!(await $c.gus.cfValidate($p, [acb_lobranCd, ica_arvStDt, ica_arvEndDt]))) {
    return;
  }
  // 조회일자 from ~ to 체크	
  if (!(await $c.gus.cfIsAfterDate($p, ica_arvStDt.getValue(), ica_arvEndDt.getValue()))) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // "시작일자가 종료일자 이전이어야 합니다."
    ica_arvStDt.focus();
    return;
  }
  $c.sbm.execute($p, sbm_retrieve);
};

//-------------------------------------------------------------------------
// 본선작업계획 투입가능인원 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = function () {
  $c.sbm.execute($p, sbm_retrieveMan);
};

//-------------------------------------------------------------------------
// 본선작업계획 hold별 물량정보 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve3 = async function () {
  ds_condition.set("cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "cvsslMgntNo"));
  var rs = await $c.sbm.execute($p, sbm_retrieveHold);
  if (rs.responseJSON.resultDataSet[0].Code == 0) {
    var rowCnt = ds_hold.getRowCount();
    txt_totalRows3.setValue(rowCnt);
  }
};

//-------------------------------------------------------------------------
// 본선작업계획 첨부파일 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve4 = async function () {
  ds_condition.set("cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "cvsslMgntNo"));
  var rs = await $c.sbm.execute($p, sbm_retrieveFile);
  if (rs.responseJSON.resultDataSet[0].Code == 0) {
    var fileJson = [];
    // 총 조회건수 표시
    if (ds_attach.getRowCount() > 0) {
      // attachFileDesc   : "중기 배정 결과.xlsx"
      // attachFileId     : "0001"
      // attachFileNm     : "중기 배정 결과.xlsx"
      // attachFilePath   : "cm/bc/cstmrcardmgnt/cstmrcardmgnt/중기 배정 결과[1_10101_260211114802680].xlsx"
      // attachFileSiz    : "4113"
      // onReqNo          : "200708210378"
      // regDtm           : "02/11 11:48"
      // rowStatus        : "R"
      // selfTransClntNo  : "100477"
      // seq              : "1"
      for (var i = 0; i < ds_attach.getRowCount(); i++) {
        var attachFilePath = ds_attach.getCellData(i, "attachFilePath");
        var fileStoredPath = attachFilePath.substr(0, attachFilePath.lastIndexOf('/') + 1);
        var storedFileNm = attachFilePath.substr(attachFilePath.lastIndexOf('/') + 1);
        var fileInfoData = {
          FILE_EXPLAIN: ds_attach.getCellData(i, "attachFileDesc"),
          FILE_SIZE: ds_attach.getCellData(i, "attachFileSiz"),
          FILE_STORED_PATH: fileStoredPath,
          ORIGIN_FILE_NM: ds_attach.getCellData(i, "attachFileNm"),
          STORED_FILE_NM: storedFileNm,
          chk: "0",
          evidClsNm: "",
          hiddenKey: "",
          preView: "",
          receptYn: "",
          rowStatus: ds_attach.getCellData(i, "rowStatus"),
          slipKndNm: "",
          slipNo: "",
          status: ""
        };
        fileJson.push(fileInfoData);
      }
    }
    gr_attachFile.setData(fileJson);
  }
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  scwin.curRow = ds_cvsslInfo.getRowPosition();
  var modifyRowCnt = ds_cvsslInfo.getModifiedIndex().length;
  if (modifyRowCnt > 0) {
    if (!(await $c.gus.cfValidate($p, [gr_cvsslInfo]))) return;
    if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
      $c.sbm.execute($p, sbm_save);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["본선계획수립대상"]); // @은(는) 변경된 사항이 없습니다
  }
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Save2 = async function () {
  scwin.curRow2 = ds_hold.getRowPosition();
  var modifyRowCnt = ds_hold.getModifiedIndex().length;
  if (modifyRowCnt > 0) {
    if (!(await $c.gus.cfValidate($p, [gr_hold]))) return;
    if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
      $c.sbm.execute($p, sbm_save2);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["Hold별 물량정보"]); // @은(는) 변경된 사항이 없습니다
  }
};

