scwin.f_AddRow = function () {
  var rowIndex = ds_hold.insertRow();
  ds_hold.setRowPosition(rowIndex);
  gr_hold.setFocusedCell(rowIndex, 0, false);
  ds_hold.setCellData(ds_hold.getRowPosition(), "cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "cvsslMgntNo"));
  ds_hold.setCellData(ds_hold.getRowPosition(), "holdNo", ds_hold.getRowPosition() + 1);
  if (ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "ioClsNm") == "수입") {
    ds_hold.setCellData(ds_hold.getRowPosition(), "impExpClsCd", "I");
  } else {
    ds_hold.setCellData(ds_hold.getRowPosition(), "impExpClsCd", "O");
  }
};

//-------------------------------------------------------------------------
// 행복사
//------------------------------------------------------------------------- 
scwin.f_CopyRow = function () {
  var bfRow = ds_hold.getRowPosition();
  var rowIndex = ds_hold.insertRow();
  ds_hold.setRowPosition(rowIndex);
  gr_hold.setFocusedCell(rowIndex, 0, false);
  ds_hold.setCellData(ds_hold.getRowPosition(), "cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "cvsslMgntNo"));
  ds_hold.setCellData(ds_hold.getRowPosition(), "holdNo", ds_hold.getRowPosition() + 1);
  if (ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "ioClsNm") == "수입") {
    ds_hold.setCellData(ds_hold.getRowPosition(), "impExpClsCd", "I");
  } else {
    ds_hold.setCellData(ds_hold.getRowPosition(), "impExpClsCd", "O");
  }
  ds_hold.setCellData(ds_hold.getRowPosition(), "commCd", ds_hold.getCellData(bfRow, "commCd"));
  ds_hold.setCellData(ds_hold.getRowPosition(), "commNm", ds_hold.getCellData(bfRow, "commNm"));
  ds_hold.setCellData(ds_hold.getRowPosition(), "qty", ds_hold.getCellData(bfRow, "qty"));
  ds_hold.setCellData(ds_hold.getRowPosition(), "wt", ds_hold.getCellData(bfRow, "wt"));
  ds_hold.setCellData(ds_hold.getRowPosition(), "cbm", ds_hold.getCellData(bfRow, "cbm"));
};
