// 드래그 할 셀선택
scwin.f_DataDragBf = function (grdobj, dsobj, row, colid) {
  if (grdobj.ColumnProp(colid, "DragMode") != "TRUE") return false;
  if (dsobj.getCellData(row, colid).toString().trim() == "" || dsobj.getCellData(row, colid) == null) {
    return false;
  }
  if (grdobj.ColumnProp(colid, "DragMode") == "TRUE") {
    scwin.tmp_colid = colid;
    scwin.tmp_grdnm = grdobj.id;
    if (colid == "staffNo") {
      scwin.tmp_staffNo = dsobj.getCellData(row, "staffNo");
      scwin.tmp_staffNm = dsobj.getCellData(row, "staffNm");
    } else if (colid == "staffNm") {
      scwin.tmp_staffNo = dsobj.getCellData(row, "staffNo");
      scwin.tmp_staffNm = dsobj.getCellData(row, "staffNm");
    }
    return true;
  } else {
    return false;
  }
};

// 드래그중
scwin.f_DataDragging = function (grobj, row, colid) {
  if (row < 1) return false;
  return true;
  if (scwin.tmp_colid == "staffNo") {
    if (scwin.tmp_colid == "cfmanEmpNo") {
      if (grobj.id != scwin.tmp_grdnm) {
        if (ds_cvsslInfo.getCellData(row, scwin.tmp_colid).trim().length == 0) {
          return true;
        }
      }
    }
  } else {
    if (scwin.tmp_colid == colid && grobj.id != scwin.tmp_grdnm) {
      if (ds_cvsslInfo.getCellData(row, scwin.tmp_colid).trim().length == 0) {
        return true;
      }
    }
  }
  return false;
};

// 드래그후 드롭
scwin.f_DataDropAf = function (lnkObj, tgtObj, row, colid, data) {
  if (scwin.tmp_colid == "staffNo" || scwin.tmp_colid == "staffNm") {
    lnkObj.setCellData(row, "cfmanEmpNo", scwin.tmp_staffNo);
    lnkObj.setCellData(row, "cfmanEmpNm", scwin.tmp_staffNm);
  }
  scwin.tmp_grdnm = "";
  scwin.tmp_colid = "";
  return true;
};
