scwin.sbm_retrieve_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    // 총 조회건수 표시
    var rowCnt = ds_cvsslInfo.getRowCount();
    txt_totalRows.setValue(rowCnt);
    if (rowCnt == 0) {
      $c.gus.cfDisableAllBtn($p);
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
    } else {
      ds_cvsslInfo.setRowPosition(0);
      $c.gus.cfEnableAllBtn($p);
      scwin.f_Retrieve2();
      scwin.f_Retrieve3();
      scwin.f_Retrieve4();
    }
    gr_cvsslInfo.setColumnStyle("cvsslMgntNo", "text-decoration", "underline");
    gr_cvsslInfo.setColumnStyle("cvsslMgntNo", "cursor", "pointer");
  }
};
